#include<bits/stdc++.h>
using namespace std;
int l=1,r=0;
long long t[300010],c[300010],f[300010],n,s,q[300010];
long long X(int x)
{
    return c[x];
}
long long Y(int x)
{
    return f[x];
}
long long K(int x)
{
    return t[x]+s;
}
int search(int L,int R,long long s)
{
    int best=r;
    while(L<=R)
    {
        int mid=(L+R)>>1;
        if(Y(q[mid+1])-Y(q[mid])>s*(X(q[mid+1])-X(q[mid])))
        {
            R=mid-1;
            best=mid;
        }
        else
        {
            L=mid+1;
        }
    }
    return q[best];
}
int main()
{
    scanf("%lld%lld",&n,&s);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld",&t[i],&c[i]);
        t[i]+=t[i-1];
        c[i]+=c[i-1];
    }
    q[++r]=0;
    for(int i=1;i<=n;i++)
    {
        int p=search(l,r,K(i));
        f[i]=f[p]+s*(c[n]-c[p])+t[i]*(c[i]-c[p]);
        while(l<r&&((Y(q[r])-Y(q[r-1]))*(X(i)-X(q[r])))>=(Y(i)-Y(q[r]))*(X(q[r])-X(q[r-1])))
        {
            r--;
        }
        q[++r]=i;
    }
    printf("%lld",f[n]);
    return 0;
}
